--
-- Table structure for table `merchandise`
--

DROP TABLE IF EXISTS `merchandise`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `merchandise` (
  `merch_id` int(11) NOT NULL AUTO_INCREMENT,
  `seller_id` int(11) DEFAULT NULL,
  `item_name` varchar(100) DEFAULT NULL,
  `category` enum('Apparel','Accessories','Bundling Package','Stationery') NOT NULL,
  `price` decimal(10,2) NOT NULL,
  `platform_fee_percent` decimal(5,2) DEFAULT 10.00,
  `stock` int(11) NOT NULL,
  `description` text DEFAULT NULL,
  `is_cs_ugm_themed` tinyint(1) DEFAULT 0,
  `is_bundling` tinyint(1) DEFAULT 0 COMMENT '0 = Single, 1 = Paket Bundling',
  `status_approval` enum('Pending','Approved','Rejected') DEFAULT 'Approved',
  `open_date` datetime DEFAULT NULL,
  `close_date` datetime DEFAULT NULL,
  `event_id` int(11) DEFAULT NULL,
  PRIMARY KEY (`merch_id`),
  KEY `fk_seller` (`seller_id`),
