INSERT INTO `merchandise` VALUES (1,202,'Oversized Heavy-Cotton Streetwear Tee \"Hello World\"','Apparel',350000.00,10.00,20,'Kaos modis ala distro hypebeast. Bahan tebal, cutting oversized kekinian. Keren untuk hangout.',1,0,'Approved','2026-01-01 00:00:00','2026-12-31 23:59:59',1),(2,110,'Authentic Suede & Leather Varsity Jacket','Apparel',1250000.00,10.00,12,'Jaket varsity dengan lengan full kulit asli dan bordir 3D. Sangat modis dan hangat.',1,0,'Approved','2026-02-01 00:00:00','2026-04-30 23:59:59',1),(3,88,'Titanium Alloy & Braided Leather Lanyard','Accessories',250000.00,10.00,25,'Bukan lanyard biasa. Tali kulit asli anyam dengan pengait titanium. Sangat elegan untuk ID Card kantor.',1,0,'Approved','2025-01-01 00:00:00','2025-12-31 23:59:59',1),(4,92,'Reversible Corduroy Bucket Hat (Korean Style)','Accessories',180000.00,10.00,20,'Topi bucket bahan korduroi premium yang bisa dipakai bolak-balik. Lucu dan kece!',1,0,'Approved','2026-03-01 00:00:00','2026-08-31 23:59:59',2),(5,180,'Sapphire Crystal Automatic Watch \"Code is Poetry\"','Accessories',3500000.00,10.00,5,'Jam tangan mekanik mewah dengan kaca safir anti-gores. Hanya diproduksi 5 unit di dunia.',1,0,'Approved','2026-04-01 00:00:00','2026-05-15 23:59:59',2),(6,74,'Magsafe Powerbank & Smart Thermos Welcome Kit','Bundling Package',550000.00,10.00,15,'Paket modern: Powerbank wireless kekinian dan termos suhu digital.',1,1,'Approved','2025-03-01 00:00:00','2025-06-30 23:59:59',2),(7,214,'Ultra-Premium Leather Director Bundle (1 of 10)','Bundling Package',2500000.00,10.00,10,'Edisi Terbatas: Tas kerja kulit asli dengan pin emas logo alumni. Sangat eksklusif.',1,1,'Approved','2026-04-10 00:00:00','2026-06-15 23:59:59',3),(8,170,'VIP Artisan Reunion Gift Box','Bundling Package',850000.00,10.00,15,'Kotak kado kayu mahoni berisi suvenir premium untuk kolektor.',1,1,'Approved','2026-10-01 00:00:00','2027-02-10 23:59:59',3),(9,28,'Signed Hardcover: \"The Silicon Valley Playbook\"','Stationery',450000.00,10.00,10,